--
-- DocGuardian demo seed — Garnet .NET 8 vs .NET 6 build conflict.
-- GENERATED by backend/scripts/gen_seed.py — do not hand-edit; re-run the
-- generator instead (the embeddings are real 384-dim fastembed vectors).
--

CREATE EXTENSION IF NOT EXISTS vector;
SET search_path TO public;

CREATE TABLE IF NOT EXISTS documents (
    doc_id        TEXT PRIMARY KEY,
    repo          TEXT NOT NULL,
    path          TEXT NOT NULL,
    branch        TEXT,
    byte_size     INTEGER,
    commit_sha    TEXT,
    commit_author TEXT,
    commit_date   TIMESTAMPTZ,
    content_hash  TEXT,
    fetched_at    TIMESTAMPTZ,
    owner             TEXT,
    title             TEXT,
    acl               TEXT[] DEFAULT '{}',
    health            TEXT,
    importance        REAL,
    last_verified_sha TEXT,
    last_verified_at  TIMESTAMPTZ,
    updated_at        TIMESTAMPTZ,
    summary           TEXT,
    original_content  TEXT,
    original_path     TEXT,
    ai_content        TEXT,
    ai_rewritten      BOOLEAN DEFAULT FALSE,
    rationale         TEXT
);

CREATE TABLE IF NOT EXISTS chunks (
    chunk_id          TEXT PRIMARY KEY,
    doc_id            TEXT NOT NULL REFERENCES documents(doc_id) ON DELETE CASCADE,
    repo              TEXT NOT NULL,
    heading_path      TEXT[],
    ordinal           INTEGER,
    text              TEXT NOT NULL,
    token_count       INTEGER,
    line_start        INTEGER,
    line_end          INTEGER,
    contains_commands BOOLEAN,
    commit_sha        TEXT,
    commit_date       TIMESTAMPTZ,
    content_hash      TEXT,
    embedding         VECTOR(384)
);

CREATE TABLE IF NOT EXISTS edges (
    edge_id     TEXT PRIMARY KEY,
    from_doc    TEXT NOT NULL,
    to_doc      TEXT NOT NULL,
    type        TEXT NOT NULL,
    weight      REAL,
    reason      TEXT,
    anchor_text TEXT,
    line        INTEGER,
    created_by  TEXT,
    commit_sha  TEXT
);

CREATE TABLE IF NOT EXISTS proposals (
    proposal_id  TEXT PRIMARY KEY,
    doc_id       TEXT,
    action       TEXT NOT NULL,
    status       TEXT NOT NULL DEFAULT 'proposed',
    risk_level   TEXT,
    confidence   REAL,
    payload      JSONB NOT NULL,
    created_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at   TIMESTAMPTZ NOT NULL DEFAULT now(),
    applied_at   TIMESTAMPTZ
);

CREATE TABLE IF NOT EXISTS provenance (
    entry_id             TEXT PRIMARY KEY,
    doc_id               TEXT,
    proposal_id          TEXT,
    action               TEXT NOT NULL,
    approved_by          TEXT NOT NULL,
    approved_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    previous_version_ref TEXT,
    new_version_ref      TEXT,
    evidence_snapshot    JSONB DEFAULT '[]',
    confidence           REAL,
    reason               TEXT
);

CREATE TABLE IF NOT EXISTS analysis_snapshots (
    snapshot_id         TEXT PRIMARY KEY,
    taken_at            TIMESTAMPTZ NOT NULL DEFAULT now(),
    repo                TEXT,
    total_docs          INTEGER,
    quality_avg         REAL,
    broken_links        INTEGER,
    stale_detected      INTEGER,
    conflicts_detected  INTEGER,
    duplicates_detected INTEGER,
    orphan_count        INTEGER,
    at_risk_count       INTEGER,
    payload             JSONB
);

CREATE INDEX IF NOT EXISTS idx_chunks_doc_id ON chunks(doc_id);
CREATE INDEX IF NOT EXISTS idx_chunks_repo ON chunks(repo);
CREATE INDEX IF NOT EXISTS idx_edges_from ON edges(from_doc);
CREATE INDEX IF NOT EXISTS idx_edges_to ON edges(to_doc);
CREATE INDEX IF NOT EXISTS idx_proposals_status ON proposals(status);
CREATE INDEX IF NOT EXISTS idx_proposals_doc ON proposals(doc_id);
CREATE INDEX IF NOT EXISTS idx_provenance_doc ON provenance(doc_id);
CREATE INDEX IF NOT EXISTS idx_provenance_proposal ON provenance(proposal_id);
CREATE INDEX IF NOT EXISTS idx_analysis_snapshots_taken ON analysis_snapshots(taken_at);
CREATE INDEX IF NOT EXISTS idx_analysis_snapshots_repo ON analysis_snapshots(repo);
CREATE INDEX IF NOT EXISTS idx_chunks_embedding ON chunks USING hnsw (embedding vector_cosine_ops);

